import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsEscapeCharacterSet_whenEscapeCharacterIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withEscape((Character) null);
        // Use reflection to set escapeCharacter to null forcibly
        Field escapeCharacterField = CSVFormat.class.getDeclaredField("escapeCharacter");
        escapeCharacterField.setAccessible(true);

        // CSVFormat is immutable, withEscape returns a new instance, so we need to create a new instance to modify
        // But since escapeCharacter is final, we cannot set it directly on the instance.
        // Instead, we create a subclass to bypass immutability for testing or use reflection to remove final modifier.

        // Remove final modifier from the field
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(escapeCharacterField, escapeCharacterField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        escapeCharacterField.set(format, null);

        assertFalse(format.isEscapeCharacterSet());
    }

    @Test
    void testIsEscapeCharacterSet_whenEscapeCharacterIsSet() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withEscape('\\');
        Field escapeCharacterField = CSVFormat.class.getDeclaredField("escapeCharacter");
        escapeCharacterField.setAccessible(true);

        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(escapeCharacterField, escapeCharacterField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        escapeCharacterField.set(format, Character.valueOf('\\'));

        assertTrue(format.isEscapeCharacterSet());
    }
}
